        if having:
            having_parts = []
            for h in having:
                func = h.get('function', '').upper()
                column = h.get('column', '*')
                operator = h.get('operator', '=').upper()
                value = h.get('value')

                if func not in ALLOWED_AGGREGATE_FUNCTIONS:
                    raise ValueError(f"Invalid aggregate function in HAVING: {func}")
                if operator not in ALLOWED_OPERATORS:
                    raise ValueError(f"Invalid operator in HAVING: {operator}")
